# Day 7: Dictionaries
student = {"name": "Ruban", "age": 25, "skills": ["Python", "SQL"]}

# Access
print(f"Name: {student['name']}")
print(f"Email: {student.get('email', 'Not found')}")  # safe

# Add/Update
student["email"] = "ruban@example.com"
student["age"] = 26

# Iterate
for key, val in student.items():
    print(f"  {key}: {val}")

# Nested dict (like JSON)
employees = {
    "E001": {"name": "Alice", "role": "ML Engineer", "salary": 120000},
    "E002": {"name": "Bob", "role": "Data Analyst", "salary": 80000}
}
for eid, info in employees.items():
    print(f"{eid}: {info['name']} — {info['role']}")

# Character frequency (interview classic)
text = "hello world"
freq = {}
for ch in text:
    if ch != " ":
        freq[ch] = freq.get(ch, 0) + 1
print(f"Frequency: {freq}")
